# Configurá tu usuario para el campo `created_by`
usuario = "1"
fecha_actual = datetime.now().strftime("%Y-%m-%d %H:%M:%S")

# Limpiamos el string para procesar las líneas
lineas = [line.strip().rstrip(',') for line in datos_originales.strip().split('\n') if line.strip()]

# Armamos los nuevos inserts
nuevos_registros = []
for linea in lineas:
    nueva_linea = linea.rstrip(')') + f", '{usuario}', '{fecha_actual}')"
    nuevos_registros.append(nueva_linea)

# Encabezado nuevo insert
insert_final = "INSERT INTO produccion_agricola_historial (id, fecha, año, mes, semana, hoja_produccion, tipo_movimiento, desglose_movimiento, ubicacion, lugar_prod, rubro, producto, unidad_medida, cantidad, created_by, created_at) VALUES\n"
insert_final += ",\n".join(nuevos_registros) + ";"

for i, linea in enumerate(nuevos_registros, start=1):
    cantidad_valores = linea.strip().strip('()').split(',')
    if len(cantidad_valores) != 16:
        print(f"🚨 Línea {i} tiene {len(cantidad_valores)} valores: {linea}")


# Guardamos en archivo .sql
output_path = "insert_convertido.sql"
with open(output_path, "w", encoding="utf-8") as file:
    file.write(insert_final)

